import java.net.http.*;
import java.net.URI;
import java.net.http.HttpRequest.BodyPublishers;

/**
 * Demonstrates HTTP method semantics and REST API design.
 * Uses Java's built-in HttpClient (Java 11+) for examples.
 */
public class HttpRestDemo {

    // ── REST Resource Design ──────────────────────────────────────────
    // Resource: /users (collection), /users/{id} (individual)
    // Collection:
    //   GET    /users              → list users
    //   POST   /users              → create user → 201 Created + Location header
    // Individual:
    //   GET    /users/42           → get user 42 → 200 or 404
    //   PUT    /users/42           → replace user 42 (full update) → 200
    //   PATCH  /users/42           → partial update → 200
    //   DELETE /users/42           → delete → 204 No Content
    // Nested:
    //   GET    /users/42/orders    → orders for user 42
    //   POST   /users/42/orders    → create order for user 42
    //   GET    /users/42/orders/7  → specific order

    // ── Idempotency Explained ─────────────────────────────────────────
    static void demonstrateIdempotency() {
        System.out.println("=== Idempotency ===");
        System.out.println("GET    /users/42 — call 100x → same result, no side effect");
        System.out.println("DELETE /users/42 — call 3x   → 204, 404, 404 (still 'deleted')");
        System.out.println("PUT    /users/42 — call 5x   → same user state each time");
        System.out.println("POST   /users    — call 3x   → creates 3 different users!");
        System.out.println("                             → NOT idempotent");
        System.out.println();
        System.out.println("Safe  = no server-side state change: GET, HEAD, OPTIONS");
        System.out.println("Idempotent = same effect on repeat: GET, PUT, DELETE, HEAD, OPTIONS");
        System.out.println("Not idempotent: POST, PATCH (sometimes)");
    }

    // ── Status Codes with Context ─────────────────────────────────────
    static void statusCodeGuide() {
        System.out.println("\n=== Status Codes (with when to use) ===");
        System.out.println("200 OK           — GET success, PUT success");
        System.out.println("201 Created      — POST success; include Location header");
        System.out.println("204 No Content   — DELETE success; body is empty");
        System.out.println("304 Not Modified — response unchanged (ETag matched)");
        System.out.println("400 Bad Request  — invalid JSON, missing required field");
        System.out.println("401 Unauthorized — no token, expired token (auth required)");
        System.out.println("403 Forbidden    — valid token but wrong role/permission");
        System.out.println("404 Not Found    — resource doesn't exist");
        System.out.println("409 Conflict     — duplicate (email already registered)");
        System.out.println("422 Unprocessable— validation failed (email format wrong)");
        System.out.println("429 Too Many Req — rate limit exceeded");
        System.out.println("500 Server Error — unhandled exception, DB down");
        System.out.println("502 Bad Gateway  — upstream service returned bad response");
        System.out.println("503 Unavailable  — service down/overloaded; add Retry-After header");
        System.out.println();
        System.out.println("Interview trap: 401 vs 403");
        System.out.println("  401 = 'prove who you are' (send credentials/token)");
        System.out.println("  403 = 'I know who you are, but you can't do this'");
    }

    // ── HTTP Client (Java 11+) ────────────────────────────────────────
    static void httpClientExamples() throws Exception {
        HttpClient client = HttpClient.newBuilder()
            .connectTimeout(java.time.Duration.ofSeconds(10))
            .build();

        // GET request
        HttpRequest getReq = HttpRequest.newBuilder()
            .uri(URI.create("https://jsonplaceholder.typicode.com/users/1"))
            .header("Accept", "application/json")
            .GET()
            .build();

        // POST with JSON body
        HttpRequest postReq = HttpRequest.newBuilder()
            .uri(URI.create("https://jsonplaceholder.typicode.com/users"))
            .header("Content-Type", "application/json")
            .POST(BodyPublishers.ofString("{\"name\":\"Alice\",\"email\":\"alice@example.com\"}"))
            .build();

        // Send synchronously
        HttpResponse<String> resp = client.send(getReq, HttpResponse.BodyHandlers.ofString());
        System.out.println("\nGET status: " + resp.statusCode());
        System.out.println("Location header: " + resp.headers().firstValue("content-type").orElse("none"));
    }

    public static void main(String[] args) throws Exception {
        demonstrateIdempotency();
        statusCodeGuide();
        // Uncomment to make real HTTP calls:
        // httpClientExamples();

        System.out.println("\n=== REST vs SOAP vs GraphQL ===");
        System.out.println("REST:     HTTP + JSON, stateless, resource URLs, cacheable");
        System.out.println("SOAP:     XML envelope, WSDL, strict contract, WS-Security");
        System.out.println("GraphQL:  single /graphql endpoint, client defines shape");
        System.out.println("gRPC:     HTTP/2, binary Protobuf, streaming, type-safe");
        System.out.println("WebSocket: ws://, full-duplex, persistent connection");
    }
}

public class WebSecurityConcepts {

    // ── TLS Handshake (what HTTPS does) ──────────────────────────────
    static void tlsHandshake() {
        System.out.println("=== TLS 1.3 Handshake (simplified) ===");
        System.out.println("1. Client → Server: ClientHello");
        System.out.println("   - Supported TLS versions (1.2, 1.3)");
        System.out.println("   - Supported cipher suites (AES-GCM, ChaCha20)");
        System.out.println("   - Random bytes for key derivation");
        System.out.println();
        System.out.println("2. Server → Client: ServerHello + Certificate");
        System.out.println("   - Chosen cipher suite");
        System.out.println("   - Server's X.509 certificate (contains public key)");
        System.out.println("   - Certificate signed by CA (DigiCert, Let's Encrypt)");
        System.out.println();
        System.out.println("3. Client: Verify certificate");
        System.out.println("   - Is it signed by a trusted CA? (browser trust store)");
        System.out.println("   - Is the domain name in the certificate?");
        System.out.println("   - Is it expired?");
        System.out.println();
        System.out.println("4. Key exchange: Derive shared symmetric key (no key sent over wire)");
        System.out.println("   - ECDHE (Ephemeral Diffie-Hellman) — forward secrecy");
        System.out.println();
        System.out.println("5. Both sides encrypt with symmetric key (AES-256-GCM)");
        System.out.println("   - Asymmetric (RSA/EC) only used for key exchange, not data");
        System.out.println("   - Why? Symmetric is 1000x faster than asymmetric encryption");
        System.out.println();
        System.out.println("TLS 1.3: 1-RTT handshake (vs TLS 1.2's 2-RTT)");
        System.out.println("HTTPS only hides the body — domain name visible in SNI extension");
    }

    // ── CORS (Cross-Origin Resource Sharing) ─────────────────────────
    static void cors() {
        System.out.println("\n=== CORS ===");
        System.out.println("Same-Origin Policy: browser blocks JS from reading responses");
        System.out.println("from a different origin (protocol + host + port).");
        System.out.println();
        System.out.println("frontend: http://localhost:3000");
        System.out.println("backend:  http://localhost:8080");
        System.out.println("=> DIFFERENT ports => DIFFERENT origin => CORS required");
        System.out.println();
        System.out.println("Simple request (GET/POST with basic content-type):");
        System.out.println("  Browser sends request → server must reply with:");
        System.out.println("  Access-Control-Allow-Origin: http://localhost:3000");
        System.out.println();
        System.out.println("Preflight request (PUT/DELETE or custom headers):");
        System.out.println("  Browser: OPTIONS /api/users HTTP/1.1");
        System.out.println("           Origin: http://localhost:3000");
        System.out.println("           Access-Control-Request-Method: DELETE");
        System.out.println("  Server:  Access-Control-Allow-Origin: *");
        System.out.println("           Access-Control-Allow-Methods: GET, POST, DELETE");
        System.out.println("           Access-Control-Allow-Headers: Authorization");
        System.out.println("           Access-Control-Max-Age: 3600");
        System.out.println();
        System.out.println("Spring CORS config:");
        System.out.println("  @CrossOrigin(origins = 'http://localhost:3000')");
        System.out.println("  or SecurityConfig: cors().configurationSource(...)");
        System.out.println();
        System.out.println("Note: CORS is a BROWSER protection. Postman/curl bypass it.");
        System.out.println("Server still enforces auth — CORS ≠ security.");
    }

    // ── Cookie Security Attributes ─────────────────────────────────
    static void cookieSecurity() {
        System.out.println("\n=== Cookie Security Attributes ===");
        System.out.println("HttpOnly  — JS cannot access via document.cookie (XSS protection)");
        System.out.println("Secure    — only sent over HTTPS (prevents HTTP sniffing)");
        System.out.println("SameSite  — controls cross-site sending:");
        System.out.println("  Strict  = never sent cross-site (breaks OAuth redirects)");
        System.out.println("  Lax     = sent on top-level navigation GET (default modern browsers)");
        System.out.println("  None    = always sent; requires Secure flag (for embedded APIs)");
        System.out.println("Domain    — which subdomains receive the cookie");
        System.out.println("Path      — which URL paths receive the cookie");
        System.out.println("Max-Age   — seconds until expiry (0 = delete immediately)");
        System.out.println();
        System.out.println("JWT storage options:");
        System.out.println("  localStorage: simple but XSS risk (JS can read)");
        System.out.println("  HttpOnly cookie: no XSS but CSRF risk → use SameSite=Strict");
        System.out.println("  Memory only: secure but lost on refresh");
        System.out.println("  Recommended: HttpOnly + Secure + SameSite=Strict cookie");
    }

    public static void main(String[] args) {
        tlsHandshake();
        cors();
        cookieSecurity();
    }
}

