public class Q1 {
    public static void main(String[] args) {
        System.out.println("REST API Design — Order Management");
        System.out.println();
        System.out.println("List all orders for user 42:");
        System.out.println("  GET /users/42/orders");
        System.out.println("  200 OK — [{id, status, total, createdAt}, ...]");
        System.out.println("  Supports: ?status=PENDING&page=0&size=20");
        System.out.println();
        System.out.println("Get order 7 for user 42:");
        System.out.println("  GET /users/42/orders/7");
        System.out.println("  200 OK — {id, status, items, total}");
        System.out.println("  404 if order 7 doesn't exist or belongs to different user");
        System.out.println();
        System.out.println("Create new order for user 42:");
        System.out.println("  POST /users/42/orders");
        System.out.println("  Body: {items: [{productId, qty}, ...], shippingAddr: '...'}");
        System.out.println("  201 Created + Location: /users/42/orders/8");
        System.out.println("  400 if validation fails, 409 if product out of stock");
        System.out.println();
        System.out.println("Update order 7 status:");
        System.out.println("  PATCH /users/42/orders/7");
        System.out.println("  Body: {status: 'SHIPPED'}");
        System.out.println("  200 OK — updated order");
        System.out.println("  422 if status transition invalid (DELIVERED→PENDING)");
        System.out.println();
        System.out.println("Delete cancelled order 7:");
        System.out.println("  DELETE /users/42/orders/7");
        System.out.println("  204 No Content (success, empty body)");
        System.out.println("  404 if order not found");
        System.out.println("  409 Conflict if order is not in CANCELLED status");
        System.out.println();
        System.out.println("List items in order 7:");
        System.out.println("  GET /users/42/orders/7/items");
        System.out.println("  200 OK — [{productId, name, qty, unitPrice}, ...]");
        System.out.println();
        System.out.println("Key decisions:");
        System.out.println("  - Nested /users/{uid}/orders ensures ownership context");
        System.out.println("  - PATCH for status (partial), not PUT (would need full body)");
        System.out.println("  - 204 (not 200) for DELETE — no response body needed");
        System.out.println("  - 409 for business rule violation vs 400 for bad input");
    }
}

