import java.util.Map;

public class Q2 {
    static int classifyScenario(String scenario) {
        String s = scenario.toLowerCase();
        if (s.contains("created") || s.contains("new user") || s.contains("post")) return 201;
        if (s.contains("delete") || s.contains("nothing to return")) return 204;
        if (s.contains("not exist") || s.contains("does not")) return 404;
        if (s.contains("no token") || s.contains("expired token") || s.contains("no auth")) return 401;
        if (s.contains("not admin") || s.contains("not allowed") || s.contains("permission")) return 403;
        if (s.contains("invalid") || s.contains("format") || s.contains("validation")) return 422;
        if (s.contains("already") || s.contains("duplicate") || s.contains("conflict")) return 409;
        if (s.contains("rate") || s.contains("limit") || s.contains("too many")) return 429;
        if (s.contains("database") || s.contains("crash") || s.contains("failed")) return 500;
        if (s.contains("succeeded") || s.contains("success") || s.contains("get")) return 200;
        return 500;
    }

    public static void main(String[] args) {
        Map<String, Integer> tests = Map.of(
            "GET request succeeded",             200,
            "POST created new user",              201,
            "DELETE succeeded, nothing to return",204,
            "Resource does not exist",            404,
            "No token in request",                401,
            "Token valid but user is not admin",  403,
            "Email format is invalid",            422,
            "Email already registered",           409,
            "Client sent 100 req/sec, limit 10",  429,
            "Database connection failed",         500
        );

        int pass = 0, fail = 0;
        for (Map.Entry<String, Integer> e : tests.entrySet()) {
            int actual = classifyScenario(e.getKey());
            boolean ok = actual == e.getValue();
            System.out.printf("%s%n  Expected: %d | Got: %d | %s%n%n",
                e.getKey(), e.getValue(), actual, ok ? "PASS" : "FAIL");
            if (ok) pass++; else fail++;
        }
        System.out.println("Results: " + pass + " pass, " + fail + " fail");
    }
}
